   439→// CompactBlockMetas merges many block metas into one, combining its source blocks together
   440→// and adjusting compaction level. Min/Max time of result block meta covers all input blocks.
   441→func CompactBlockMetas(uid ulid.ULID, blocks ...*BlockMeta) *BlockMeta {
   442→	res := &BlockMeta{
   443→		ULID: uid,
   444→	}
   445→
   446→	sources := map[ulid.ULID]struct{}{}
   447→	mint := blocks[0].MinTime
   448→	maxt := blocks[0].MaxTime
   449→
   450→	for _, b := range blocks {
   451→		if b.MinTime < mint {
   452→			mint = b.MinTime
   453→		}
   454→		if b.MaxTime > maxt {
   455→			maxt = b.MaxTime
   456→		}
   457→		if b.Compaction.Level > res.Compaction.Level {
   458→			res.Compaction.Level = b.Compaction.Level
   459→		}
   460→		for _, s := range b.Compaction.Sources {
   461→			sources[s] = struct{}{}
   462→		}
   463→		res.Compaction.Parents = append(res.Compaction.Parents, BlockDesc{
   464→			ULID:    b.ULID,
   465→			MinTime: b.MinTime,
   466→			MaxTime: b.MaxTime,
   467→		})
   468→	}
   469→	res.Compaction.Level++
   470→
   471→	for s := range sources {
   472→		res.Compaction.Sources = append(res.Compaction.Sources, s)
   473→	}
   474→	slices.SortFunc(res.Compaction.Sources, func(a, b ulid.ULID) int {
   475→		return a.Compare(b)
   476→	})
   477→
   478→	res.MinTime = mint
   479→	res.MaxTime = maxt
   480→	return res
   481→}
   482→
   483→// Compact creates a new block in the compactor's directory from the blocks in the
   484→// provided directories.
   485→func (c *LeveledCompactor) Compact(dest string, dirs []string, open []*Block) ([]ulid.ULID, error) {
   486→	return c.CompactWithBlockPopulator(dest, dirs, open, DefaultBlockPopulator{})
   487→}
   488→
   489→func (c *LeveledCompactor) CompactWithBlockPopulator(dest string, dirs []string, open []*Block, blockPopulator BlockPopulator) ([]ulid.ULID, error) {
   490→	var (
   491→		blocks []BlockReader
   492→		bs     []*Block
   493→		metas  []*BlockMeta
   494→		uids   []string
   495→	)
   496→	start := time.Now()
   497→
   498→	for _, d := range dirs {
   499→		select {
   500→		case <-c.ctx.Done():
   501→			return nil, c.ctx.Err()
   502→		default:
   503→		}
   504→
   505→		meta, _, err := readMetaFile(d)
   506→		if err != nil {
   507→			return nil, err
   508→		}
   509→
   510→		var b *Block
   511→
   512→		// Use already open blocks if we can, to avoid
   513→		// having the index data in memory twice.
   514→		for _, o := range open {
   515→			if meta.ULID == o.Meta().ULID {
   516→				b = o
   517→				break
   518→			}
   519→		}
   520→
   521→		if b == nil {
   522→			var err error
   523→			b, err = OpenBlock(c.logger, d, c.chunkPool, c.postingsDecoderFactory)
   524→			if err != nil {
   525→				return nil, err
   526→			}
   527→			defer b.Close()
   528→		}
   529→
   530→		metas = append(metas, meta)
   531→		blocks = append(blocks, b)
   532→		bs = append(bs, b)
   533→		uids = append(uids, meta.ULID.String())
   534→	}
   535→
   536→	uid := ulid.MustNew(ulid.Now(), rand.Reader)
   537→
   538→	meta := CompactBlockMetas(uid, metas...)
   539→	err := c.write(dest, meta, blockPopulator, blocks...)
   540→	if err == nil {
   541→		if meta.Stats.NumSamples == 0 {
   542→			for _, b := range bs {
   543→				b.meta.Compaction.Deletable = true
   544→				n, err := writeMetaFile(c.logger, b.dir, &b.meta)
   545→				if err != nil {
   546→					c.logger.Error(
   547→						"Failed to write 'Deletable' to meta file after compaction",
   548→						"ulid", b.meta.ULID,
   549→					)
   550→				}
   551→				b.numBytesMeta = n
   552→			}
   553→			c.logger.Info(
   554→				"compact blocks resulted in empty block",
   555→				"count", len(blocks),
   556→				"sources", fmt.Sprintf("%v", uids),
   557→				"duration", time.Since(start),
   558→			)
   559→			return nil, nil
   560→		}
