#### compactBlocks Method (lines 1721-1763)
**File:** `/go/agent-index-go/testdata/fixtures/go/db.go`

```go
func (db *DB) compactBlocks() (err error) {
	// Check for compactions of multiple blocks.
	for {
		// If we have a lot of blocks to compact the whole process might take
		// long enough that we end up with a HEAD block that needs to be written.
		// Check if that's the case and stop compactions early.
		if db.head.compactable() && !db.waitingForCompactionDelay() {
			db.logger.Warn("aborting block compactions to persist the head block")
			return nil
		}

		plan, err := db.compactor.Plan(db.dir)
		if err != nil {
			return fmt.Errorf("plan compaction: %w", err)
		}
		if len(plan) == 0 {
			break
		}

		select {
		case <-db.stopc:
			return nil
		default:
		}

		uids, err := db.compactor.Compact(db.dir, plan, db.blocks)
		if err != nil {
			return fmt.Errorf("compact %s: %w", plan, err)
		}

		if err := db.reloadBlocks(); err != nil {
			// Handle error and cleanup...
			return errors.Join(errs...)
		}
	}

	return nil
}
```

**Flow:**
1. Loop indefinitely checking for compactable blocks
2. Call `compactor.Plan(db.dir)` to get list of block directories to compact
3. If plan is empty, break the loop
4. Call `compactor.Compact(db.dir, plan, db.blocks)` to compact the blocks
5. Call `reloadBlocks()` to reload and manage block lifecycle
6. Repeat until no more compactions are needed

